#region -- Helpers de consola
# Semaforo para sincronizar la confirmacion Y/N
$script:confirmPending = $false
$script:deviceCodeValue = ""

function Write-Console {
    param([string]$Text, [string]$Type = "white")
    $color = switch ($Type) {
        "ok"   { $colorOK }
        "info" { $colorInfo }
        "warn" { $colorWarn }
        "step" { $colorStep }
        "red"  { $colorRed }
        default { [System.Drawing.Color]::FromArgb(230, 237, 243) }
    }
    $rtbConsole.Invoke([Action]{
        $rtbConsole.SelectionStart = $rtbConsole.TextLength
        $rtbConsole.SelectionLength = 0
        $rtbConsole.SelectionColor = $color
        $rtbConsole.AppendText($Text + "`n")
        $rtbConsole.ScrollToCaret()
    })
}

function Update-Step {
    param([int]$Step)
    $prgBar.Invoke([Action]{
        $prgBar.Value = $Step
        for ($i = 0; $i -lt 5; $i++) {
            if ($i -lt $Step) {
                $stepLabels[$i].ForeColor = $colorOK
            } elseif ($i -eq $Step) {
                $stepLabels[$i].ForeColor = $colorInfo
            } else {
                $stepLabels[$i].ForeColor = $colorMuted
            }
        }
    })
}

function Show-DeviceCode {
    param([string]$Code)
    # Panel desactivado - ventana PS es visible durante auth
}

function Hide-DeviceCode {
    # Panel desactivado
}

function Show-Confirm {
    param([string]$Msg)
    $pnlConfirm.Invoke([Action]{
        $lblConfirmText.Text = $Msg
        $pnlConfirm.Visible = $true
    })
}

function Hide-Confirm {
    $pnlConfirm.Invoke([Action]{ $pnlConfirm.Visible = $false })
}
#endregion

#region -- Eventos botones Device Code / Confirm
$btnUsarCodigo.Add_Click({
    $codigo = $txtDCInput.Text.Trim().ToUpper()
    if ($codigo.Length -ge 6) {
        [System.Windows.Forms.Clipboard]::SetText($codigo)
        try { [System.IO.File]::WriteAllText($script:dcodeF, "CODE:$codigo", [System.Text.Encoding]::UTF8) } catch {}
        $script:deviceCodeValue = $codigo
        $lblDCCode.Text = $codigo
        Write-Console "  Codigo ingresado: $codigo - copiado al portapapeles." "ok"
        Write-Console "  Pega el codigo en el browser y autenticate." "warn"
    }
})

$btnCopyCode.Add_Click({
    $c = if ($script:deviceCodeValue -and $script:deviceCodeValue -notmatch "WAITING|AUTHDONE") { $script:deviceCodeValue } else { $txtDCInput.Text.Trim() }
    if ($c) { [System.Windows.Forms.Clipboard]::SetText($c); Write-Console "  Codigo copiado: $c" "ok" }
})

$btnOpenBrowser.Add_Click({
    Start-Process "https://microsoft.com/devicelogin"
    Write-Console "  [OK] Abriendo browser en microsoft.com/devicelogin" "ok"
})

$btnSi.Add_Click({
    Hide-Confirm
    $script:confirmPending = $false
    try { [System.IO.File]::WriteAllText($script:confirmF, "YES", [System.Text.Encoding]::UTF8) } catch {}
    Write-Console "  [OK] Confirmado (Y)" "ok"
})

$btnNo.Add_Click({
    Hide-Confirm
    $script:confirmPending = $false
    try { [System.IO.File]::WriteAllText($script:confirmF, "NO", [System.Text.Encoding]::UTF8) } catch {}
    Write-Console "  [X]  Cancelado (N)" "red"
})

$btnClear.Add_Click({
    $rtbConsole.Clear()
    $prgBar.Value = 0
    $pnlDeviceCode.Visible = $false
    $pnlConfirm.Visible = $false
    for ($i = 0; $i -lt 5; $i++) { $stepLabels[$i].ForeColor = $colorMuted }
})
#endregion

#region -- Evento Copiar Comando PS
$btnCmd.Add_Click({
    $client = $txtClient.Text.Trim()
    $tenant = $txtTenant.Text.Trim()
    $modo   = $cmbModo.SelectedIndex

    if ([string]::IsNullOrEmpty($client)) { $client = "NombreCliente" }
    if ([string]::IsNullOrEmpty($tenant)) { $tenant = "TU-TENANT-ID" }

    $modeFlag = switch ($modo) {
        1       { "" }
        2       { "-OnlyCreateApp" }
        default { "-SkipAppCreation" }
    }

    $masterScript = Join-Path $ScriptRoot "MasterExport-MEM.ps1"
    $cmd = "powershell.exe -ExecutionPolicy Bypass -File `"$masterScript`" -TenantId `"$tenant`" -ClientName `"$client`" $modeFlag"
    [System.Windows.Forms.Clipboard]::SetText($cmd)
    Write-Console "  Comando copiado al portapapeles." "ok"
})
#endregion

#region -- Evento principal Exportar


$btnExport.Add_MouseEnter({ $btnExport.BackColor = $colorBlueDark })
$btnExport.Add_MouseLeave({ $btnExport.BackColor = $colorBlue })

$btnExport.Add_Click({
    $client = $txtClient.Text.Trim()
    $tenant = $txtTenant.Text.Trim()
    $upn    = $txtUPN.Text.Trim()
    $modo   = $cmbModo.SelectedIndex

    if ([string]::IsNullOrEmpty($tenant)) {
        Write-Console "  [X]  Completa el Tenant ID." "red"; return
    }
    if ($modo -eq 0 -and [string]::IsNullOrEmpty($client)) {
        Write-Console "  [X]  Completa el Nombre del Cliente." "red"; return
    }
    if (($modo -eq 1 -or $modo -eq 2) -and [string]::IsNullOrEmpty($client)) { $client = "AppRegistration" }
    $masterScript = Join-Path $ScriptRoot "MasterExport-MEM.ps1"
    if (-not (Test-Path $masterScript)) {
        Write-Console "  [X]  No se encontro MasterExport-MEM.ps1 en: $ScriptRoot" "red"; return
    }
    $modeFlag = switch ($modo) {
        1 { "" }
        2 { "-OnlyCreateApp" }
        default { "-SkipAppCreation" }
    }

    $rtbConsole.Clear()
    $prgBar.Value = 0
    for ($i=0; $i -lt 5; $i++) { $stepLabels[$i].ForeColor = $colorMuted }
    $pnlDeviceCode.Visible = $false
    $pnlConfirm.Visible    = $false

    $script:logF     = [System.IO.Path]::Combine($env:TEMP, "IDK_log.tmp")
    $script:confirmF = [System.IO.Path]::Combine($env:TEMP, "IDK_confirm.tmp")
    $script:dcodeF   = [System.IO.Path]::Combine($env:TEMP, "IDK_dcode.tmp")

    [System.IO.File]::WriteAllText($script:logF,     "", [System.Text.Encoding]::UTF8)
    [System.IO.File]::WriteAllText($script:confirmF, "", [System.Text.Encoding]::UTF8)
    [System.IO.File]::WriteAllText($script:dcodeF,   "", [System.Text.Encoding]::UTF8)

    Write-Console "=================================================" "step"
    Write-Console "  IntuneDocKit -- Iniciando exportacion"           "info"
    Write-Console "  Cliente : $client"                               "white"
    Write-Console "  Tenant  : $tenant"                               "white"
    if ($upn) { Write-Console "  Usuario : $upn"                      "white" }
    Write-Console "=================================================" "step"
    Update-Step 0

    if ($script:activeJob) {
        Stop-Job  $script:activeJob -ErrorAction SilentlyContinue
        Remove-Job $script:activeJob -ErrorAction SilentlyContinue
    }

    $script:activeJob = Start-Job -ArgumentList $script:logF,$script:confirmF,$script:dcodeF,$masterScript,$tenant,$client,$modeFlag,$upn -ScriptBlock {
        param($logF,$confirmF,$dcodeF,$masterSc,$tenantId,$clientNm,$modeFlg,$scriptUpn)

        function wl {
            param([string]$m, [string]$t = 'white')
            [System.IO.File]::AppendAllText($logF, "$t|$m`n", [System.Text.Encoding]::UTF8)
        }

        function Process-Line {
            param([string]$line, $stdin)
            if ($null -eq $line -or $line.Trim() -eq "") { return }
            if    ($line -match '\[OK\]')                { wl $line 'ok'   }
            elseif($line -match '={3,}|PASO \d')         { wl $line 'step' }
            elseif($line -match '\[!\]')                 { wl $line 'warn' }
            elseif($line -match '\[X\]|Error')           { wl $line 'red'  }
            elseif($line -match 'Y/N') {
                wl $line 'warn'
                [System.IO.File]::WriteAllText($confirmF, "PENDING:Conectar al tenant. Continuar?", [System.Text.Encoding]::UTF8)
                $w = 0
                while ([System.IO.File]::ReadAllText($confirmF) -like "PENDING*") {
                    Start-Sleep -Milliseconds 400; $w += 400
                    if ($w -gt 180000) { break }
                }
                $ans = [System.IO.File]::ReadAllText($confirmF).Trim()
                if ($ans -eq "YES") {
                    wl "Respondiendo Y - esperando Device Code..." "ok"
                    $stdin.WriteLine("Y")
                    # Escribir WAITING para que la GUI abra el browser
                    [System.IO.File]::WriteAllText($dcodeF, "WAITING", [System.Text.Encoding]::UTF8)
                } else { wl "Respondiendo N" "warn"; $stdin.WriteLine("N") }
            }
            elseif($line -match 'enter the code|devicelogin|To sign in') {
                wl $line 'warn'
                if ($line -match 'enter the code ([A-Z0-9]{6,9})') {
                    [System.IO.File]::WriteAllText($dcodeF, "CODE:$($matches[1])", [System.Text.Encoding]::UTF8)
                }
            }
            elseif($line -match 'user principal name|Please specify your user') {
                wl $line 'warn'; $stdin.WriteLine($scriptUpn)
            }
            elseif($line -match 'Client name for|Nombre del cliente') {
                $stdin.WriteLine($clientNm)
            }
            elseif($line -match 'does not exist|Create it\? \(Y/N\)') {
                wl $line 'warn'; $stdin.WriteLine("Y")
            }
            elseif($line -match 'Export path \(e\.g') {
                $stdin.WriteLine("")
            }
            elseif($line -match '^Windows PowerShell|^Copyright.*Microsoft|^Install the latest|^https://aka') {
                # ignorar banner
            }
            elseif($line -match 'microsoft.com|login.microsoft|devicelogin') {
                    wl $line 'warn'
                    if ($line -match '([A-Z0-9]{8,9})') {
                        [System.IO.File]::WriteAllText($dcodeF, "CODE:$($matches[1])", [System.Text.Encoding]::UTF8)
                    }
                }
                else { 
                    # Log todo para debug - ver que manda MSAL
                    wl $line 'white' 
                }
        }

        function Run-Proc {
            param([string]$exe, [string]$argStr)

            $psi = New-Object System.Diagnostics.ProcessStartInfo
            $psi.FileName               = $exe
            $psi.Arguments              = $argStr
            $psi.UseShellExecute        = $false
            $psi.RedirectStandardOutput = $true
            $psi.RedirectStandardError  = $true
            $psi.RedirectStandardInput  = $true
             $psi.CreateNoWindow         = $true
             $psi.WindowStyle            = [System.Diagnostics.ProcessWindowStyle]::Hidden
            if ($scriptUpn) { $psi.EnvironmentVariables["INTUMEDOCKIT_UPN"] = $scriptUpn }
            $psi.EnvironmentVariables["INTUMEDOCKIT_GUI"] = "1"

            $proc = [System.Diagnostics.Process]::Start($psi)
            wl "[OK] PID=$($proc.Id)" "ok"

            # Leer stdout linea por linea (el Job corre en background, no bloquea la GUI)
            while (-not $proc.StandardOutput.EndOfStream) {
                $line = $proc.StandardOutput.ReadLine()
                if ($null -ne $line) { Process-Line $line $proc.StandardInput }
            }
            $proc.WaitForExit()
            $errTxt = $proc.StandardError.ReadToEnd()
            if ($errTxt -and $errTxt.Trim()) { wl $errTxt 'red' }
            wl "Exit=$($proc.ExitCode)" "step"
        }

        wl "=== Job iniciado ===" "step"

        if (-not (Test-Path $masterSc)) {
            wl "[X] No se encontro: $masterSc" "red"
            wl "===DONE===" "ok"; return
        }


        try {
            $argStr = "-NoProfile -ExecutionPolicy Bypass -File `"$masterSc`" -TenantId `"$tenantId`" -ClientName `"$clientNm`""
            if ($modeFlg -and $modeFlg.Trim() -ne "") { $argStr += " $modeFlg" }

            if ($modeFlg -like "*SkipAppCreation*") {
                # Modo exportar existente: oculto con captura
                wl "=== Iniciando exportacion ===" "step"
                Run-Proc "powershell.exe" $argStr
            } else {
                # Modo crear App Registration: ventana visible (necesita WAM/browser)
                wl "=== Iniciando creacion de App Registration ===" "step"
                wl "Se abrira una ventana de PowerShell para autenticacion." "warn"
                wl "Completa el proceso en esa ventana." "warn"
                $proc = Start-Process "powershell.exe" -ArgumentList $argStr -PassThru -Wait
                wl "Proceso App Registration finalizado. Exit=$($proc.ExitCode)" "step"
            }
        } catch {
            wl "[X] $($_.Exception.Message)" "red"
        }

        wl "===DONE===" "ok"
    }

    Write-Console "  Job ID: $($script:activeJob.Id)" "step"

    $script:lastLogPos      = 0
    $script:confirmPending  = $false
    $script:deviceCodeValue = ""

    if ($script:exportTimer) { $script:exportTimer.Stop() }
    $script:exportTimer = New-Object System.Windows.Forms.Timer
    $script:exportTimer.Interval = 400

    $script:exportTimer.Add_Tick({
        try {
            $txt = [System.IO.File]::ReadAllText($script:logF, [System.Text.Encoding]::UTF8)
            $allLines = $txt -split "`n" | Where-Object { $_.Trim() -ne "" }
            if ($allLines.Count -gt $script:lastLogPos) {
                $newLines = $allLines[$script:lastLogPos..($allLines.Count - 1)]
                foreach ($line in $newLines) {
                    $parts = $line -split "\|", 2
                    if ($parts.Count -ge 2) { $ltype = $parts[0].Trim() } else { $ltype = "white" }
                    if ($parts.Count -ge 2) { $lmsg = $parts[1].TrimEnd("`r") } else { $lmsg = $line }
                    Write-Console $lmsg $ltype
                    if ($lmsg -match "PASO 1")                              { Update-Step 0 }
                    if ($lmsg -match "PASO 2")                              { Update-Step 1 }
                    if ($lmsg -match "PASO 3")                              { Update-Step 2 }
                    if ($lmsg -match "PASO 4")                              { Update-Step 3 }
                    if ($lmsg -match "PASO 5|Exportando|Iniciando exportac") { Update-Step 4 }
                    if ($lmsg -match "COMPLETADO|Document saved|AUTHDONE")  { Update-Step 5 }
                    if ($lmsg -match "===DONE===") {
                        $script:exportTimer.Stop()
                        Update-Step 5
                        Hide-DeviceCode; Hide-Confirm
                        Write-Console "" "white"
                        Write-Console "  Proceso finalizado correctamente." "ok"
                    }
                }
                $script:lastLogPos = $allLines.Count
            }
        } catch {}

        try {
            $dc = [System.IO.File]::ReadAllText($script:dcodeF, [System.Text.Encoding]::UTF8).Trim()
            if ($dc -eq "WAITING" -and $script:deviceCodeValue -ne "WAITING") {
                $script:deviceCodeValue = "WAITING"
                Start-Process "https://microsoft.com/devicelogin"
                Write-Console "  Abriendo browser en microsoft.com/devicelogin..." "warn"
                Write-Console "  El codigo aparecera en la ventana de PowerShell de la barra de tareas." "warn"
                Write-Console "  Ingresalo en el browser y autenticate con tu cuenta de Intune." "warn"
                # Panel desactivado
                # Monitorear transcript para obtener el codigo real
                $script:transcriptF = [System.IO.Path]::Combine($env:TEMP, "IDK_transcript.tmp")
            } elseif ($dc -eq "AUTHDONE" -and $script:deviceCodeValue -ne "AUTHDONE") {
                $script:deviceCodeValue = "AUTHDONE"
                Hide-DeviceCode
                Write-Console "  Autenticacion completada correctamente." "ok"
            } elseif ($dc -match "^CODE:(.+)$") {
                $code = $matches[1]
                if ($code -ne $script:deviceCodeValue) {
                    $script:deviceCodeValue = $code
                    # Device code panel desactivado - ventana PS es visible
                }
            }
            # Monitorear transcript para codigo real de MSAL
            if ($script:transcriptF -and (Test-Path $script:transcriptF) -and $script:deviceCodeValue -eq "WAITING") {
                try {
                    $tc = [System.IO.File]::ReadAllText($script:transcriptF, [System.Text.Encoding]::UTF8)
                    if ($tc -match "enter the code ([A-Z0-9]{6,9})" -or $tc -match "code ([A-Z0-9]{8,9}) to auth") {
                        $realCode = $matches[1]
                        $script:deviceCodeValue = $realCode
                        # Panel desactivado
                        [System.IO.File]::WriteAllText($script:dcodeF, "CODE:$realCode", [System.Text.Encoding]::UTF8)
                    }
                } catch {}
            }
        } catch {}

        if (-not $script:confirmPending) {
            try {
                $cf = [System.IO.File]::ReadAllText($script:confirmF, [System.Text.Encoding]::UTF8)
                if ($cf -match "^PENDING:(.+)") {
                    $script:confirmPending = $true
                    Show-Confirm $matches[1].TrimEnd("`r`n")
                }
            } catch {}
        }

        $jState = $script:activeJob.State
        if ($jState -eq "Completed" -or $jState -eq "Failed" -or $jState -eq "Stopped") {
            $script:exportTimer.Stop()
            Hide-DeviceCode; Hide-Confirm
            if ($jState -eq "Failed") {
                try { $r = $script:activeJob.ChildJobs[0].JobStateInfo.Reason.Message; Write-Console "  [X] $r" "red" } catch {}
                try { $o = Receive-Job $script:activeJob 2>&1 | Out-String; if($o.Trim()){Write-Console $o "red"} } catch {}
            }
            if ($rtbConsole.Text -notmatch "Proceso finalizado") {
                Write-Console "" "white"
                Write-Console "  Proceso finalizado." "ok"
            }
        }
    })

    $script:exportTimer.Start()
})

$form.Controls.AddRange(@($pnlHeader, $pnlLeft, $pnlRight, $pnlFooter))
$form.Add_Shown({ $form.Activate() })
[void]$form.ShowDialog()
